#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_WORD_LENGTH 100
#define TABLE_SIZE 1000

typedef struct {
    char word[MAX_WORD_LENGTH];
    int count;
} HashNode;

typedef struct {
    HashNode table[TABLE_SIZE];
} HashTable;

int hash_function(const char *word) {
    int hash = 0;
    for (int i = 0; word[i]; i++) {
        hash = (hash * 31 + word[i]) % TABLE_SIZE;
    }
    return hash;
}

void init_hash_table(HashTable *table) {
    for (int i = 0; i < TABLE_SIZE; i++) {
        table->table[i].word[0] = '\0';
        table->table[i].count = 0;
    }
}

void add_sound_suggest(HashTable *table, const char *preword) {
    if (preword == NULL || preword[0] == '\0') {
        return;
    }

    int index = hash_function(preword);
    HashNode *node = &table->table[index];

    if (strcmp(node->word, preword) != 0) {
        strcpy(node->word, preword);
        node->count = 1;
    } else {
        node->count++;
    }
}

int main() {
    HashTable table;
    init_hash_table(&table);

    add_sound_suggest(&table, "hello");
    add_sound_suggest(&table, "world");
    add_sound_suggest(&table, "hello");

    printf("hello count: %d\n", table.table[hash_function("hello")].count);
    printf("world count: %d\n", table.table[hash_function("world")].count);

    return 0;
}
