DWORD GetServiceStartType(const std::wstring& serviceName) {
    SC_HANDLE hSCManager = OpenSCManager(NULL, NULL, SC_MANAGER_ALL_ACCESS);
    if (hSCManager == NULL) {
        std::cerr << "Failed to open SCManager: " << GetLastError() << std::endl;
        return ERROR_SERVICE_DISABLED;
    }

    SC_HANDLE hService = OpenService(hSCManager, serviceName.c_str(), SERVICE_QUERY_CONFIG);
    if (hService == NULL) {
        std::cerr << "Failed to open service: " << GetLastError() << std::endl;
        CloseServiceHandle(hSCManager);
        return ERROR_SERVICE_DISABLED;
    }

    DWORD bytesNeeded = 0;
    if (!QueryServiceConfig(hService, NULL, 0, &bytesNeeded) && GetLastError() != ERROR_INSUFFICIENT_BUFFER) {
        std::cerr << "Failed to query service config: " << GetLastError() << std::endl;
        CloseServiceHandle(hService);
        CloseServiceHandle(hSCManager);
        return ERROR_SERVICE_DISABLED;
    }

    LPQUERY_SERVICE_CONFIG config = (LPQUERY_SERVICE_CONFIG)LocalAlloc(LPTR, bytesNeeded);
    if (config == NULL) {
        std::cerr << "Failed to allocate memory for service config: " << GetLastError() << std::endl;
        CloseServiceHandle(hService);
        CloseServiceHandle(hSCManager);
