// Define the ModeChange structure
struct ModeChange {
    char changeType;
    char mode;
};

// Function to convert mode changes to mode letters
std::string ToModeLetters(const std::vector<ModeChange>& modeChanges, int malinelen) {
    std::string modeLetters;
    for (const auto& change : modeChanges) {
        if (modeLetters.length() >= malinelen) {
            break;
        }
        if (change.changeType == '+') {
            modeLetters += change.mode;
        } else if (change.changeType == '-') {
            auto it = modeLetters.find(change.mode);
            if (it != std::string::npos) {
                modeLetters.erase(it, 1);
            }
        }
    }
    return modeLetters;
}

