    std::vector<ModeChange> modeChanges = {
        {'+', 'A'}, {'+', 'B'}, {'-', 'A'}, {'+', 'C'}
    };
    int malinelen = 4;
    std::string result = ToModeLetters(modeChanges, malinelen);
    std::cout << "Mode Letters: " << result << std::endl;
    return 0;
}
