bool establishSecureMySQLConnection(const char* host, const char* user, const char* password, const char* database) {
    MYSQL* conn = mysql_init(nullptr);
    if (!conn) {
        std::cerr << "MySQL initialization failed: " << mysql_error(nullptr) << std::endl;
        return false;
    }

    if (mysql_ssl_set(conn, nullptr, nullptr, nullptr, nullptr, nullptr)) {
        std::cerr << "SSL initialization failed: " << mysql_error(conn) << std::endl;
        mysql_close(conn);
        return false;
    }

    if (mysql_options(conn, MYSQL_OPT_SSL_MODE, (char*)"REQUIRED")) {
        std::cerr << "Setting SSL mode failed: " << mysql_error(conn) << std::endl;
        mysql_close(conn);
        return false;
    }

    if (mysql_real_connect(conn, host, user, password, database, 0, nullptr, 0)) {
        std::cout << "Connection established successfully." << std::endl;
        mysql_close(conn);
        return true;
    } else {
