    if (hSCManager == NULL) {
        throw std::runtime_error("Failed to open service control manager");
    }

    SC_HANDLE hService = CreateService(
        hSCManager,
        m_serviceName.c_str(),
        m_serviceDisplayName.c_str(),
        SERVICE_ALL_ACCESS,
        SERVICE_WIN32_OWN_PROCESS,
        SERVICE_AUTO_START,
        SERVICE_ERROR_NORMAL,
        quotedPath.c_str(),
        NULL,
        NULL,
        NULL,
        NULL,
        NULL
    );

    if (hService == NULL) {
        CloseServiceHandle(hSCManager);
        throw std::runtime_error("Failed to create service");
    }

    // Start the service
    if (!StartService(hService, 0, NULL)) {
        CloseServiceHandle(hService);
        CloseServiceHandle(hSCManager);
        throw std::runtime_error("Failed to start service");
    }

    // Check the service status
    SERVICE_STATUS status;
    if (!QueryServiceStatus(hService, &status)) {
        CloseServiceHandle(hService);
        CloseServiceHandle(hSCManager);
        throw std::runtime_error("Failed to query service status");
    }

    if (status.dwCurrentState != SERVICE_RUNNING) {
        CloseServiceHandle(hService);
        CloseServiceHandle(hSCManager);
        throw std::runtime_error("Service did not start successfully");
    }

    CloseServiceHandle(hService);
    CloseServiceHandle(hSCManager);
}
