    json_state_t state;
    char *buffer;
    size_t buffer_size;
    size_t buffer_index;
} json_parser_t;

void json_internal_read_object(json_parser_t *parser, const char *json_data, size_t json_length) {
    parser->buffer = (char *)malloc(JSON_OBJECT_SIZE);
    if (parser->buffer == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return;
    }
    parser->buffer_size = JSON_OBJECT_SIZE;
    parser->buffer_index = 0;
    parser->state = JSON_OBJECT_START;

    for (size_t i = 0; i < json_length; i++) {
        char ch = json_data[i];

        switch (parser->state) {
            case JSON_OBJECT_START:
                if (ch == '{') {
                    parser->state = JSON_KEY;
                } else {
                    parser->state = JSON_ERROR;
                }
                break;
            case JSON_KEY:
                if (ch == '"') {
                    parser->state = JSON_COLON;
                } else {
                    parser->state = JSON_ERROR;
                }
                break;
            case JSON_COLON:
                if (ch == ':') {
                    parser->state = JSON_VALUE;
                } else {
                    parser->state = JSON_ERROR;
                }
                break;
            case JSON_VALUE:
                if (ch == '"') {
                    parser->state = JSON_COMMA;
                } else if (ch == '\\') {
                    parser->state = JSON_IN_ESCAPE;
                } else {
                    if (parser->buffer_index >= parser->buffer_size) {
                        // Handle buffer overflow
                        fprintf(stderr, "Buffer overflow detected\n");
                        free(parser->buffer);
                        return;
