                    parser->buffer[parser->buffer_index++] = ch;
                }
                break;
            case JSON_COMMA:
                if (ch == ',') {
                    parser->state = JSON_KEY;
                } else if (ch == '}') {
                    parser->state = JSON_OBJECT_END;
                } else {
                    parser->state = JSON_ERROR;
                }
