#define MAX_DEPTH 1000

typedef enum { ADD, SUB, MUL, DIV, NONE } Operator;

typedef struct {
    Operator op;
    double left;
    double right;
} Node;

double eval6(Node *node, int depth) {
    if (depth >= MAX_DEPTH) {
        fprintf(stderr, "Recursion depth exceeded\n");
        exit(EXIT_FAILURE);
    }
    switch (node->op) {
        case ADD:
            return eval6(node->left, depth + 1) + eval6(node->right, depth + 1);
        case SUB:
