void S_reg_set_capture_string(const char *pattern, char **output) {
    regex_t regex;
    int ret;

    // Compile the regex pattern
    ret = regcomp(&regex, pattern, REG_EXTENDED | REG_NEWLINE);
    if (ret != 0) {
        fprintf(stderr, "Failed to compile regex pattern\n");
        return;
    }

    // Allocate memory for the output string
    *output = (char *)malloc(256);
    if (*output == NULL) {
        fprintf(stderr, "Failed to allocate memory for output string\n");
        regfree(&regex);
        return;
    }

    // Execute the regex and capture the string
    regmatch_t matches[10];
    ret = regexec(&regex, pattern, 10, matches, 0);
    if (ret == 0) {
        // Copy the captured string to the output buffer
        strncpy(*output, pattern + matches[0].rm_so, matches[0].rm_eo - matches[0].rm_so);
        (*output)[matches[0].rm_eo - matches[0].rm_so] = '\0';
    } else if (ret == REG_NOMATCH) {
        fprintf(stderr, "No match found\n");
        free(*output);
        *output = NULL;
    } else {
        fprintf(stderr, "Regex match error\n");
        free(*output);
        *output = NULL;
    }

    // Free the regex object
    regfree(&regex);
}
