static Status GetRowPartitionTensor(OpKernelContext* ctx, int dim, string partition_type, Tensor* row_partition_tensor) {
  const Tensor& tensor = ctx->input(dim);
  if (tensor.dtype() != DT_INT64) {
    return errors::InvalidArgument("Row partition tensors must be of type int64.");
  }
  if (partition_type == "row") {
    *row_partition_tensor = tensor.flat<INDEX_TYPE>();
  } else if (partition_type == "col") {
    *row_partition_tensor = tensor.flat<INDEX_TYPE>().reverse();
