#include <pjsip.h>

pjsip_response *create_sip_response(pjsip_dialog *dlg, pjsip_status_code status_code, const pjsip_str_t *reason)
{
    pjsip_response *response = NULL;
    pjsip_tx_data *tdata = NULL;

    // Lock the dialog
    pjsip_dlg_lock(dlg);

    // Create a SIP response
    if (pjsip_endpt_create_response(dlg->endpt, dlg, status_code, reason, NULL, &response) != PJ_SUCCESS)
    {
        // Handle error
        pjsip_dlg_unlock(dlg);
        return NULL;
    }

    // Create a transaction data for sending the response
    if (pjsip_endpt_create_tx_data(dlg->endpt, &tdata) != PJ_SUCCESS)
    {
        // Handle error
        pjsip_msg_dec_ref((pjsip_msg*)response);
        pjsip_dlg_unlock(dlg);
        return NULL;
    }

    // Add the response to the transaction data
    tdata->msg_info.msg = (pjsip_msg*)response;

    // Send the response
    if (pjsip_dlg_send_response(dlg, tdata) != PJ_SUCCESS)
    {
        // Handle error
        pjsip_tx_data_dec_ref(tdata);
        pjsip_dlg_unlock(dlg);
        return NULL;
    }

    // Unlock the dialog
    pjsip_dlg_unlock(dlg);

    return response;
}
