int dsa_mod_inverse_fermat(BIGNUM *r, const BIGNUM *a, const BIGNUM *p, BN_CTX *ctx) {
    BIGNUM *tmp = BN_new();
    if (!tmp) return 0;

    // Resize BIGNUMs to prevent timing attacks
    BN_set_word(tmp, 1);
    BN_mod_exp(r, tmp, p, p, ctx);
    BN_free(tmp);

    // Compute modular inverse using Fermat's Little Theorem
    return BN_mod_exp(r, a, p, ctx);
}
