class WindowsServiceControl {
public:
    bool ChangeServiceStartType(const std::wstring& serviceName, DWORD startType) {
        SC_HANDLE hSCManager = OpenSCManager(NULL, NULL, SC_MANAGER_ALL_ACCESS);
        if (hSCManager == NULL) {
            std::cerr << "OpenSCManager failed: " << GetLastError() << std::endl;
            return false;
        }

        SC_HANDLE hService = OpenService(hSCManager, serviceName.c_str(), SERVICE_CHANGE_CONFIG);
        if (hService == NULL) {
            std::cerr << "OpenService failed: " << GetLastError() << std::endl;
            CloseServiceHandle(hSCManager);
            return false;
        }

        // Get the current service information to get the binary path
        SERVICE_STATUS_PROCESS ssStatus;
        DWORD bytesNeeded;
        if (!QueryServiceStatusEx(hService, SC_STATUS_PROCESS_INFO, (LPBYTE)&ssStatus, sizeof(SERVICE_STATUS_PROCESS), &bytesNeeded)) {
            std::cerr << "QueryServiceStatusEx failed: " << GetLastError() << std::endl;
            CloseServiceHandle(hService);
            CloseServiceHandle(hSCManager);
            return false;
        }

        // Quote the binary path to prevent unquoted service path vulnerabilities
        std::wstring quotedPath = L"\"" + ssStatus.lpServiceBinaryPathName + L"\"";

        if (!ChangeServiceConfig(hService, SERVICE_NO_CHANGE, startType, SERVICE_NO_CHANGE, quotedPath.c_str(), NULL, NULL, NULL, NULL, NULL, NULL)) {
