int AVI_read_audio(AVIContext *avi, void *buffer, int size) {
    if (avi->current_index >= avi->index_size) {
        fprintf(stderr, "Error: No more audio data available.\n");
        return -1;
    }

    AVIIndexEntry *entry = &avi->index[avi->current_index];
    if (entry->flags & AVI_INDEX_KEYFRAME) {
        fprintf(stderr, "Error: Attempted to read audio data from a keyframe.\n");
        return -1;
    }

    if (gf_fseek(avi->file, entry->offset, SEEK_SET) != 0) {
        perror("Error seeking in file");
        return -1;
    }

    int read_size = avi_read(avi, buffer, entry->size);
    if (read_size != entry->size) {
        fprintf(stderr, "Error reading audio data: %d bytes read, expected %d.\n", read_size, entry->size);
        return -1;
    }

    avi->current_index++;
    return read_size;
}
