using namespace tensorflow;

class SetOutputOp : public OpKernel {
 public:
  explicit SetOutputOp(OpKernelConstruction* context) : OpKernel(context) {
    OP_REQUIRES_OK(context, context->GetAttr("default_value", &default_value_));
  }

  void Compute(OpKernelContext* context) override {
    const Tensor& rt_input = context->input(0);
    OP_REQUIRES(context, rt_input.dims() == 2, errors::InvalidArgument("Input must be a 2D RaggedTensor"));

    TensorShape output_shape = rt_input.shape();
    output_shape.set_dim(0, rt_input.dim_size(0));
    output_shape.set_dim(1, rt_input.dim_size(1));

    Tensor* output = nullptr;
    OP_REQUIRES_OK(context, context->allocate_output(0, output_shape, &output));

    auto output_flat = output->flat<T>();
    auto rt_input_flat = rt_input.flat<T>();

    for (int i = 0; i < rt_input.dim_size(0); ++i) {
      for (int j = 0; j < rt_input.dim_size(1); ++j) {
        output_flat(i * rt_input.dim_size(1) + j) = rt_input_flat(i * rt_input.dim_size(1) + j);
      }
    }

    // Handle contiguous regions
    for (int i = 0; i < rt_input.dim_size(0); ++i) {
      for (int j = 0; j < rt_input.dim_size(1); ++j) {
        if (i > 0 && j > 0 && output_flat(i * rt_input.dim_size(1) + j) == output_flat((i - 1) * rt_input.dim_size(1) + j)) {
          output_flat(i * rt_input.dim_size(1) + j) = default_value_;
        }
      }
    }
  }

 private:
  T default_value_;
};

