#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {
    char* buffer;
    size_t size;
    size_t capacity;
} StringPool;

void poolInit(StringPool* pool, size_t initialCapacity) {
    pool->buffer = (char*)malloc(initialCapacity);
    pool->size = 0;
    pool->capacity = initialCapacity;
}

void poolAppendChar(StringPool* pool, char ch) {
    if (pool->size + 1 >= pool->capacity) {
        pool->capacity *= 2;
        pool->buffer = (char*)realloc(pool->buffer, pool->capacity);
    }
    pool->buffer[pool->size++] = ch;
    pool->buffer[pool->size] = '\0';
}

void poolStoreString(StringPool* pool, const char* str) {
    size_t len = strlen(str);
    if (pool->size + len + 1 >= pool->capacity) {
        pool->capacity = pool->size + len + 1;
        pool->buffer = (char*)realloc(pool->buffer, pool->capacity);
    }
    strcpy(pool->buffer + pool->size, str);
    pool->size += len;
}

void appendAttributeValue(StringPool* pool, const char* value) {
    poolStoreString(pool, value);
}

int main() {
    StringPool pool;
    poolInit(&pool, 100);

    const char* attributeValue = "example attribute value";
    appendAttributeValue(&pool, attributeValue);

    printf("Attribute Value: %s\n", pool.buffer);

    free(pool.buffer);
    return 0;
