int chacha20_poly1305_cipher(unsigned char *out, size_t *outlen, size_t outsize,
                              const unsigned char *in, size_t inlen,
                              const unsigned char *key, size_t keylen,
                              const unsigned char *nonce, size_t noncelen,
                              const unsigned char *ad, size_t adlen) {
    if (noncelen > 12) {
        return -1; // Nonce too long
    }

    EVP_CIPHER_CTX *ctx = EVP_CIPHER_CTX_new();
    if (!ctx) {
        return -1; // OpenSSL error
    }

    if (!EVP_EncryptInit_ex(ctx, EVP_chacha20_poly1305(), NULL, key, nonce)) {
        EVP_CIPHER_CTX_free(ctx);
        return -1; // OpenSSL error
    }

    if (!EVP_EncryptUpdate(ctx, out, outlen, in, inlen)) {
        EVP_CIPHER_CTX_free(ctx);
        return -1; // OpenSSL error
    }

    if (!EVP_EncryptFinal_ex(ctx, out + *outlen, outlen)) {
        EVP_CIPHER_CTX_free(ctx);
        return -1; // OpenSSL error
    }

    if (!EVP_CIPHER_CTX_ctrl(ctx, EVP_CTRL_CHACHA_POLY1305_AAD, adlen, (void *)ad)) {
        EVP_CIPHER_CTX_free(ctx);
        return -1; // OpenSSL error
    }

    EVP_CIPHER_CTX_free(ctx);
    return 0; // Success
}
