void shift_rfc5988_val(const char *key, zval *value, char **buf, size_t *buf_len) {
    char *quoted_value;
    size_t quoted_len;

    // Ensure the buffer is large enough to hold the key, value, and quotes
    quoted_len = strlen(key) + Z_STRLEN_P(value) + 3; // +3 for quotes and null terminator
    *buf = erealloc(*buf, *buf_len + quoted_len + 1);
    *buf_len += quoted_len + 1;

    // Append the key and open quote
    snprintf(*buf + strlen(*buf), quoted_len + 1, "\"%s\": ", key);

    // Quote the string value and append it
    quoted_value = php_addslashes(Z_STRVAL_P(value), Z_STRLEN_P(value), NULL, NULL);
    snprintf(*buf + strlen(*buf), quoted_len + 1, "\"%s\"", quoted_value);
    efree(quoted_value); // Free the temporary quoted string

    // Ensure the buffer is null-terminated
    (*buf)[*buf_len - 1] = '\0';
}

